import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.OutputStreamCallback
import java.nio.charset.StandardCharsets
import java.util.regex.Pattern

def flowFile = session.get()
if(!flowFile) return

try {
    def rowsNumber = flowFile.getAttribute('rowsNumber')
    if (!rowsNumber) {
        log.warn("Atributo 'rowsNumber' no encontrado, se omite el FlowFile.")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (rowsNumber == 'null'){
        log.warn("Atributo 'rowsNumber' es null, NO se modifica el FlowFile.")
        session.transfer(flowFile, REL_SUCCESS)
        return
    }
	def patternStr = /^(.*\n)(?:[^\r\n]*(?:\r?\n|$)){${rowsNumber}}/

    // Leer contenido
    def textRef = new StringBuilder()
    session.read(flowFile, new InputStreamCallback() {
        @Override
        void process(InputStream inputStream) throws IOException {
            textRef.append(new String(inputStream.bytes, StandardCharsets.UTF_8))
        }
    })
    def content = textRef.toString()

    // Compilar patrón (sin DOTALL, solo MULTILINE)
    def pattern = Pattern.compile(patternStr, Pattern.MULTILINE)
    def matcher = pattern.matcher(content)

    def result
    if (matcher.find()) {
        // En lugar de replaceFirst(), reconstruimos manualmente:
        def prefix = matcher.group(1)  // la primera línea
        def suffix = content.substring(matcher.end()) // el resto tras el bloque eliminado
        result = prefix + suffix
        log.info("✅ Match encontrado. Eliminadas líneas intermedias.")
    } else {
        log.warn("⚠️ No hubo match con el patrón en este contenido.")
        result = content
    }

    // Escribir nuevo contenido
    flowFile = session.write(flowFile, new OutputStreamCallback() {
        @Override
        void process(OutputStream outputStream) throws IOException {
            outputStream.write(result.getBytes(StandardCharsets.UTF_8))
        }
    })

    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("Error procesando el FlowFile: ${e.message}", e)
    session.transfer(flowFile, REL_FAILURE)
}
